package com.campkin.service;
import com.campkin.api.*; import com.campkin.api.ApiModels.*; import com.campkin.domain.*; import com.campkin.repo.*; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import org.springframework.web.multipart.MultipartFile; import java.io.*; import java.util.*;
@Service @RequiredArgsConstructor public class LeaderImportService {
 private final CampRepository camps;private final LeaderRepository leaders;private final ExcelImportService spreadsheets;
 @Transactional public LeaderImportResult importFile(UUID campId,MultipartFile file)throws IOException{Camp camp=camps.findById(campId).orElseThrow();List<Map<String,String>> rows=spreadsheets.readRows(file);if(rows.isEmpty())throw new IllegalArgumentException("The file has no leader rows");List<String> errors=new ArrayList<>();record Row(String name,String normalized,Domain.Gender gender){}List<Row> valid=new ArrayList<>();Set<String> seen=new HashSet<>();for(int i=0;i<rows.size();i++){Map<String,String> row=rows.get(i);String name=first(row,"leader name","name","leader","servant name","servant").trim().replaceAll("\\s+"," ");String normalized=NameMatcher.normalize(name);Domain.Gender gender=spreadsheets.parseGender(first(row,"gender","sex"));int number=i+2;boolean unique=!name.isBlank()&&seen.add(normalized);if(name.isBlank())errors.add("Row "+number+": leader name is missing");else if(!unique)errors.add("Row "+number+" ("+name+"): duplicate leader name");if(gender==Domain.Gender.UNKNOWN)errors.add("Row "+number+" ("+(name.isBlank()?"unnamed leader":name)+"): gender must be Male or Female");if(unique&&gender!=Domain.Gender.UNKNOWN)valid.add(new Row(name,normalized,gender));}if(!errors.isEmpty())throw new ImportValidationException(errors);int added=0,updated=0;for(Row row:valid){Leader leader=leaders.findByCampIdAndNormalizedName(campId,row.normalized()).orElse(null);if(leader==null){leader=new Leader();leader.setCamp(camp);leader.setNormalizedName(row.normalized());added++;}else updated++;leader.setName(row.name());leader.setGender(row.gender());leaders.save(leader);}return new LeaderImportResult(valid.size(),added,updated,List.of());}
 private String first(Map<String,String> row,String...keys){for(String key:keys){String value=row.getOrDefault(key,"").trim();if(!value.isBlank())return value;}return "";}
}
